import{_ as s,c as i,o as t,aN as e}from"./chunks/framework.BRm39z_l.js";const c=JSON.parse('{"title":"HTTP","description":"","frontmatter":{},"headers":[],"relativePath":"computerNetwork/03.HTTP.md","filePath":"computerNetwork/03.HTTP.md"}'),l={name:"computerNetwork/03.HTTP.md"};function n(p,a,h,r,o,T){return t(),i("div",null,a[0]||(a[0]=[e(`<h1 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#http状态码">HTTP状态码</a></li><li><a href="#get和post的区别">GET和POST的区别</a></li><li><a href="#post请求可以用于查询么-为啥不全用post呢">post请求可以用于查询么？为啥不全用post呢</a></li><li><a href="#http-请求的过程与原理">HTTP 请求的过程与原理</a></li><li><a href="#http-与-https-有哪些区别">HTTP 与 HTTPS 有哪些区别</a></li><li><a href="#http的报文结构">HTTP的报文结构</a><ul><li><a href="#http-响应报文结构">HTTP 响应报文结构</a></li></ul></li></ul></nav><h2 id="http状态码" tabindex="-1">HTTP状态码 <a class="header-anchor" href="#http状态码" aria-label="Permalink to &quot;HTTP状态码&quot;">​</a></h2><p>HTTP 状态码用于表示服务器对请求的处理结果，可以分为 5 种：</p><ul><li>1xx 服务器收到请求，需要进一步操作，例如 100 Continue。</li><li>2xx 请求成功处理，例如 200 OK。</li><li>3xx 重定向：需要进一步操作以完成请求；例如 304 Not Modified 表示资源未修改，客户端可以使用缓存。</li><li>4xx 客户端错误：请求有问题，例如 404 Not Found 表示资源不存在。</li><li>5xx 服务器错误，例如500 Internal Server Error 表示服务器内部错误。</li></ul><h2 id="get和post的区别" tabindex="-1">GET和POST的区别 <a class="header-anchor" href="#get和post的区别" aria-label="Permalink to &quot;GET和POST的区别&quot;">​</a></h2><p>GET 请求主要用于获取数据，参数附加在 URL 中，存在长度限制，且容易被浏览器缓存，有安全风险，请求是幂等的，多次请求不会改变服务器状态</p><p>POST 请求用于提交数据，参数放在请求体中，适合提交大量或敏感的数据。 请求不是幂等的，可能对服务器数据有影响。</p><h2 id="post请求可以用于查询么-为啥不全用post呢" tabindex="-1">post请求可以用于查询么？为啥不全用post呢 <a class="header-anchor" href="#post请求可以用于查询么-为啥不全用post呢" aria-label="Permalink to &quot;post请求可以用于查询么？为啥不全用post呢&quot;">​</a></h2><p>RESTful API 设计的核心是「资源 + 动作」，HTTP 方法对应动作</p><p>如果全用 POST 做查询，接口语义会完全丢失 —— 比如 <code>/api/user</code> 用 POST 既可能是「查用户」，也可能是「新增用户」，开发者必须看文档 / 代码才能区分，维护成本极高</p><p>查询类请求通常是高频且结果相对稳定的，GET 请求的缓存机制能大幅提升性能：浏览器第一次查完，会缓存结果，第二次直接从本地取，不用发请求；CDN / 网关层也能缓存 GET 请求结果，减轻后端服务器压力。</p><p>而 POST 请求默认不会被缓存，即使手动配置缓存规则，也远不如 GET 天然适配，全用 POST 会浪费缓存带来的性能优化。</p><h2 id="http-请求的过程与原理" tabindex="-1">HTTP 请求的过程与原理 <a class="header-anchor" href="#http-请求的过程与原理" aria-label="Permalink to &quot;HTTP 请求的过程与原理&quot;">​</a></h2><ul><li>在浏览器输入 URL 后，浏览器首先会通过 DNS 解析获取到服务器的 IP 地址，然后与服务器建立 TCP 连接。</li><li>TCP 连接建立后，浏览器会向服务器发送 HTTP 请求。</li><li>服务器收到请求后，会根据请求的信息处理请求。</li><li>处理完请求后，服务器会返回一个 HTTP 响应给浏览器。</li><li>浏览器收到响应后，会根据响应的信息渲染页面。然后，浏览器和服务器断开 TCP 连接。</li></ul><p>客户端发送一个请求到服务器，服务器处理请求并返回一个响应。这个过程是同步的，也就是说，客户端在发送请求后必须等待服务器的响应。在等待响应的过程中，客户端不会发送其他请求</p><h2 id="http-与-https-有哪些区别" tabindex="-1">HTTP 与 HTTPS 有哪些区别 <a class="header-anchor" href="#http-与-https-有哪些区别" aria-label="Permalink to &quot;HTTP 与 HTTPS 有哪些区别&quot;">​</a></h2><p>HTTPS 是 HTTP 的增强版，在 HTTP 的基础上加入了 SSL/TLS 协议，确保数据在传输过程中是加密的</p><p>HTTP 是明文传输的，存在数据窃听、数据篡改和身份伪造等问题。而 HTTPS 通过引入 SSL/TLS，解决了这些问题。</p><p>SSL/TLS 在加密过程中涉及到了两种类型的加密方法：</p><ul><li>非对称加密：服务器向客户端发送公钥，然后客户端用公钥加密自己的随机密钥，也就是会话密钥，发送给服务器，服务器用私钥解密，得到会话密钥</li><li>对称加密：双方用会话密钥加密通信内容</li></ul><p>客户端会通过数字证书来验证服务器的身份，数字证书由 CA 签发，包含了服务器的公钥、证书的颁发机构、证书的有效期等</p><h2 id="http的报文结构" tabindex="-1">HTTP的报文结构 <a class="header-anchor" href="#http的报文结构" aria-label="Permalink to &quot;HTTP的报文结构&quot;">​</a></h2><p>HTTP 的报文结构分为：请求报文和响应报文。两者在结构上很相似，都包含了<strong>起始行</strong>、<strong>头部</strong>和<strong>消息正文</strong></p><h3 id="http-响应报文结构" tabindex="-1">HTTP 响应报文结构 <a class="header-anchor" href="#http-响应报文结构" aria-label="Permalink to &quot;HTTP 响应报文结构&quot;">​</a></h3><div class="language-xml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HTTP/1.0 200 OK</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Content-Type: text/plain</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Content-Length: 137582</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Expires: Thu, 05 Dec 1997 16:00:00 GMT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Last-Modified: Wed, 5 August 1996 15:55:28 GMT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Server: Apache 0.84</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">html</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">body</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;沉默王二很天真&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">body</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">html</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>①、状态行</p><p>包括 HTTP 协议的版本、状态码（如 200、404）和状态消息（如 OK、NotFound）。例如：<code>HTTP/1.0 200 OK</code>。</p><p>②、响应头部</p><p>包含响应的附加信息，如服务器类型、内容类型、内容长度等。也是键值对，例如：</p><ul><li><code>Content-Type: text/plain</code>，表示响应的内容类型</li><li><code>Content-Length: 137582</code>，表示响应的内容长度</li><li><code>Expires: Thu, 05 Dec 1997 16:00:00 GMT</code>，表示资源的过期时间</li><li><code>Last-Modified: Wed, 5 August 1996 15:55:28 GMT</code>，表示资源的最后修改时间</li><li><code>Server: Apache 0.84</code>，表示服务器类型</li></ul><p>③、空行</p><p>表示响应头部结束。</p><p>④、消息正文（可选）</p><p>响应的具体内容，如 HTML 页面。不是所有的响应都有消息正文，如 204 No Content 状态码的响应。</p>`,35)]))}const E=s(l,[["render",n]]);export{c as __pageData,E as default};
